# Fuzzy Text

Canvas scanline-displacement text effect with configurable base fuzziness, hover/click intensity bursts, glitch auto-mode, gradient color support, and directional displacement.

## Use when
- Adding a glitchy hero headline on a dark landing page.
- Drawing attention to a CTA with a hover-reactive fuzzy burst effect.
- Creating a retro/cyberpunk text aesthetic with continuous glitch mode.

## Stack
- Framework: react
- Libraries: (none)

## Install
```bash
# No additional packages required
```

## Component — fuzzy-text.tsx
```tsx
import React, { useEffect, useRef } from 'react';

interface FuzzyTextProps {
  children: React.ReactNode;
  fontSize?: number | string;
  fontWeight?: string | number;
  fontFamily?: string;
  color?: string;
  enableHover?: boolean;
  baseIntensity?: number;
  hoverIntensity?: number;
  fuzzRange?: number;
  fps?: number;
  direction?: 'horizontal' | 'vertical' | 'both';
  transitionDuration?: number;
  clickEffect?: boolean;
  glitchMode?: boolean;
  glitchInterval?: number;
  glitchDuration?: number;
  gradient?: string[] | null;
  letterSpacing?: number;
  className?: string;
}

export const FuzzyText: React.FC<FuzzyTextProps> = ({
  children,
  fontSize = 'clamp(2rem, 8vw, 8rem)',
  fontWeight = 900,
  fontFamily = 'inherit',
  color = '#fff',
  enableHover = true,
  baseIntensity = 0.18,
  hoverIntensity = 0.5,
  fuzzRange = 30,
  fps = 60,
  direction = 'horizontal',
  transitionDuration = 0,
  clickEffect = false,
  glitchMode = false,
  glitchInterval = 2000,
  glitchDuration = 200,
  gradient = null,
  letterSpacing = 0,
  className = ''
}) => {
  const canvasRef = useRef<HTMLCanvasElement & { cleanupFuzzyText?: () => void }>(null);

  useEffect(() => {
    let animationFrameId: number;
    let isCancelled = false;
    let glitchTimeoutId: ReturnType<typeof setTimeout>;
    let glitchEndTimeoutId: ReturnType<typeof setTimeout>;
    let clickTimeoutId: ReturnType<typeof setTimeout>;

    const canvas = canvasRef.current;
    if (!canvas) return;

    const init = async () => {
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      const computedFontFamily = fontFamily === 'inherit' ? window.getComputedStyle(canvas).fontFamily || 'sans-serif' : fontFamily;
      const fontSizeStr = typeof fontSize === 'number' ? `${fontSize}px` : fontSize;
      const fontString = `${fontWeight} ${fontSizeStr} ${computedFontFamily}`;
      try { await document.fonts.load(fontString); } catch { await document.fonts.ready; }
      if (isCancelled) return;
      let numericFontSize: number;
      if (typeof fontSize === 'number') { numericFontSize = fontSize; } else {
        const temp = document.createElement('span'); temp.style.fontSize = fontSize;
        document.body.appendChild(temp); numericFontSize = parseFloat(window.getComputedStyle(temp).fontSize); document.body.removeChild(temp);
      }
      const text = React.Children.toArray(children).join('');
      const offscreen = document.createElement('canvas'); const offCtx = offscreen.getContext('2d');
      if (!offCtx) return;
      offCtx.font = `${fontWeight} ${fontSizeStr} ${computedFontFamily}`; offCtx.textBaseline = 'alphabetic';
      let totalWidth = 0;
      if (letterSpacing !== 0) { for (const char of text) totalWidth += offCtx.measureText(char).width + letterSpacing; totalWidth -= letterSpacing; }
      else totalWidth = offCtx.measureText(text).width;
      const metrics = offCtx.measureText(text);
      const actualLeft = metrics.actualBoundingBoxLeft ?? 0;
      const actualRight = letterSpacing !== 0 ? totalWidth : (metrics.actualBoundingBoxRight ?? metrics.width);
      const actualAscent = metrics.actualBoundingBoxAscent ?? numericFontSize;
      const actualDescent = metrics.actualBoundingBoxDescent ?? numericFontSize * 0.2;
      const textBoundingWidth = Math.ceil(letterSpacing !== 0 ? totalWidth : actualLeft + actualRight);
      const tightHeight = Math.ceil(actualAscent + actualDescent);
      const extraWidthBuffer = 10;
      offscreen.width = textBoundingWidth + extraWidthBuffer; offscreen.height = tightHeight;
      offCtx.font = `${fontWeight} ${fontSizeStr} ${computedFontFamily}`; offCtx.textBaseline = 'alphabetic';
      if (gradient && Array.isArray(gradient) && gradient.length >= 2) {
        const grad = offCtx.createLinearGradient(0, 0, offscreen.width, 0);
        gradient.forEach((c, i) => grad.addColorStop(i / (gradient.length - 1), c));
        offCtx.fillStyle = grad;
      } else offCtx.fillStyle = color;
      if (letterSpacing !== 0) {
        let xPos = extraWidthBuffer / 2;
        for (const char of text) { offCtx.fillText(char, xPos, actualAscent); xPos += offCtx.measureText(char).width + letterSpacing; }
      } else offCtx.fillText(text, extraWidthBuffer / 2 - actualLeft, actualAscent);
      const horizontalMargin = fuzzRange + 20;
      const verticalMargin = direction === 'vertical' || direction === 'both' ? fuzzRange + 10 : 0;
      canvas.width = offscreen.width + horizontalMargin * 2; canvas.height = tightHeight + verticalMargin * 2;
      ctx.translate(horizontalMargin, verticalMargin);
      let isHovering = false; let isClicking = false; let isGlitching = false;
      let currentIntensity = baseIntensity; let targetIntensity = baseIntensity;
      let lastFrameTime = 0; const frameDuration = 1000 / fps;
      const startGlitchLoop = () => {
        if (!glitchMode || isCancelled) return;
        glitchTimeoutId = setTimeout(() => {
          if (isCancelled) return;
          isGlitching = true;
          glitchEndTimeoutId = setTimeout(() => { isGlitching = false; startGlitchLoop(); }, glitchDuration);
        }, glitchInterval);
      };
      if (glitchMode) startGlitchLoop();
      const run = (timestamp: number) => {
        if (isCancelled) return;
        if (timestamp - lastFrameTime < frameDuration) { animationFrameId = window.requestAnimationFrame(run); return; }
        lastFrameTime = timestamp;
        ctx.clearRect(-fuzzRange - 20, -fuzzRange - 10, offscreen.width + 2 * (fuzzRange + 20), tightHeight + 2 * (fuzzRange + 10));
        if (isClicking || isGlitching) targetIntensity = 1;
        else if (isHovering) targetIntensity = hoverIntensity;
        else targetIntensity = baseIntensity;
        if (transitionDuration > 0) {
          const step = 1 / (transitionDuration / frameDuration);
          if (currentIntensity < targetIntensity) currentIntensity = Math.min(currentIntensity + step, targetIntensity);
          else if (currentIntensity > targetIntensity) currentIntensity = Math.max(currentIntensity - step, targetIntensity);
        } else currentIntensity = targetIntensity;
        for (let j = 0; j < tightHeight; j++) {
          let dx = 0; let dy = 0;
          if (direction === 'horizontal' || direction === 'both') dx = Math.floor(currentIntensity * (Math.random() - 0.5) * fuzzRange);
          if (direction === 'vertical' || direction === 'both') dy = Math.floor(currentIntensity * (Math.random() - 0.5) * fuzzRange * 0.5);
          ctx.drawImage(offscreen, 0, j, offscreen.width, 1, dx, j + dy, offscreen.width, 1);
        }
        animationFrameId = window.requestAnimationFrame(run);
      };
      animationFrameId = window.requestAnimationFrame(run);
      const interactiveLeft = horizontalMargin + extraWidthBuffer / 2;
      const interactiveTop = verticalMargin; const interactiveRight = interactiveLeft + textBoundingWidth; const interactiveBottom = interactiveTop + tightHeight;
      const isInsideTextArea = (x: number, y: number) => x >= interactiveLeft && x <= interactiveRight && y >= interactiveTop && y <= interactiveBottom;
      const handleMouseMove = (e: MouseEvent) => { if (!enableHover) return; const rect = canvas.getBoundingClientRect(); isHovering = isInsideTextArea(e.clientX - rect.left, e.clientY - rect.top); };
      const handleMouseLeave = () => { isHovering = false; };
      const handleClick = () => { if (!clickEffect) return; isClicking = true; clearTimeout(clickTimeoutId); clickTimeoutId = setTimeout(() => { isClicking = false; }, 150); };
      if (enableHover) { canvas.addEventListener('mousemove', handleMouseMove); canvas.addEventListener('mouseleave', handleMouseLeave); }
      if (clickEffect) canvas.addEventListener('click', handleClick);
      canvas.cleanupFuzzyText = () => {
        window.cancelAnimationFrame(animationFrameId);
        clearTimeout(glitchTimeoutId); clearTimeout(glitchEndTimeoutId); clearTimeout(clickTimeoutId);
        if (enableHover) { canvas.removeEventListener('mousemove', handleMouseMove); canvas.removeEventListener('mouseleave', handleMouseLeave); }
        if (clickEffect) canvas.removeEventListener('click', handleClick);
      };
    };
    init();
    return () => {
      isCancelled = true; window.cancelAnimationFrame(animationFrameId);
      clearTimeout(glitchTimeoutId); clearTimeout(glitchEndTimeoutId); clearTimeout(clickTimeoutId);
      if (canvas && canvas.cleanupFuzzyText) canvas.cleanupFuzzyText();
    };
  }, [children, fontSize, fontWeight, fontFamily, color, enableHover, baseIntensity, hoverIntensity, fuzzRange, fps, direction, transitionDuration, clickEffect, glitchMode, glitchInterval, glitchDuration, gradient, letterSpacing]);

  return <canvas ref={canvasRef} className={className} />;
};

export default FuzzyText;
```

