import React from 'react';
import { FuzzyText } from './Component';

export default function App() {
  return (
    <div className="relative min-h-screen w-full flex flex-col items-center justify-center bg-[#1A1A1B] p-8 font-sans overflow-hidden">
      <div className="relative z-10 p-20 rounded-3xl flex items-center justify-center">
        <FuzzyText
          fontSize="clamp(3rem, 12vw, 9rem)"
          fontWeight={900}
          color="#FFFFFF"
          enableHover={true}
          baseIntensity={0.15}
          hoverIntensity={0.5}
          fuzzRange={25}
          clickEffect={true}
          transitionDuration={200}
          direction="both"
        >
          FUZZY
        </FuzzyText>
      </div>
      <div className="mt-8 text-neutral-500 text-sm font-medium tracking-widest uppercase opacity-60">Interactive Text Effect</div>
    </div>
  );
}
